def style_normal(paragraph):
    paragraph.style = "Normal"
    fmt = paragraph.paragraph_format
    fmt.left_indent = Cm(0)
    fmt.first_line_indent = Cm(1.5)
    fmt.space_before = Pt(0)
    fmt.space_after = Pt(0)
    fmt.line_spacing_rule = WD_LINE_SPACING.ONE_POINT_FIVE
    fmt.line_spacing = 1.5
    paragraph.alignment = WD_ALIGN_PARAGRAPH.JUSTIFY


def style_biblio(paragraph):
    paragraph.style = "Normal"
    fmt = paragraph.paragraph_format
    fmt.left_indent = Cm(0)
    fmt.first_line_indent = Cm(0)
    fmt.space_before = Pt(0)
    fmt.space_after = Pt(0)
    fmt.line_spacing_rule = WD_LINE_SPACING.ONE_POINT_FIVE
    fmt.line_spacing = 1.5
    paragraph.alignment = WD_ALIGN_PARAGRAPH.JUSTIFY


def append_sections(path: Path):
    doc = Document(str(path))
    existing = {p.text.strip() for p in doc.paragraphs}
    if "Заключение" in existing or "Список используемых источников" in existing:
        print(f"Skip {path.name}: sections already exist")
        return

    while doc.paragraphs and not doc.paragraphs[-1].text.strip():
        p = doc.paragraphs[-1]._element
        p.getparent().remove(p)

    doc.add_page_break()
    heading = doc.add_paragraph("Заключение", style="Heading 1")
    heading.alignment = WD_ALIGN_PARAGRAPH.LEFT

    for text in CONCLUSION_PARAGRAPHS:
        p = doc.add_paragraph(text)
        style_normal(p)

    doc.add_page_break()
    heading = doc.add_paragraph("Список используемых источников", style="Heading 1")
    heading.alignment = WD_ALIGN_PARAGRAPH.LEFT

    for item in SOURCES:
        p = doc.add_paragraph(item)
        style_biblio(p)

    doc.save(str(path))
    print(f"Updated {path.name}")


def main():
    for path in Path(__file__).resolve().parents[1].glob("ПЗ_4П1_9_22_Хорлин_НВ*.docx"):
        append_sections(path)


if __name__ == "__main__":
    main()